I have run into the same problem using version 2.1, so I am
assuming that you havn't had a time to look at this yet.  I
have had some success by copying the InsertIdentityOperation
class into my own source code and changing the execute
method as shown below.  Feel free to do with this as you
like if you find it useful.

public void execute\(IDatabaseConnection connection,
IDataSet dataSet\)
throws DatabaseUnitException, SQLException
\{
Connection jdbcConnection = connection.getConnection\(\);
Statement statement = jdbcConnection.createStatement\(\);

try
\{
IDataSet databaseDataSet =
connection.createDataSet\(\);


// INSERT\_IDENTITY need to be enabled/disabled
inside the
// same transaction
if \(jdbcConnection.getAutoCommit\(\) == false\)
\{
throw new ExclusiveTransactionException\(\);
\}
jdbcConnection.setAutoCommit\(false\);

// Execute decorated operation one table at a time
ITableIterator iterator = dataSet.iterator\(\);
while\(iterator.next\(\)\)
\{
ITable table = iterator.getTable\(\);
String tableName =
table.getTableMetaData\(\).getTableName\(\);

ITableMetaData metaData =

databaseDataSet.getTableMetaData\(tableName\);

// enable identity insert
boolean hasIdentityColumn =
hasIdentityColumn\(metaData, connection\);

if \(hasIdentityColumn\)
\{
StringBuffer sqlBuffer = new
StringBuffer\(128\);
sqlBuffer.append\("SET IDENTITY\_INSERT "\);

sqlBuffer.append\(getQualifiedName\(connection.getSchema\(\),
metaData.getTableName\(\),
connection\)\);
sqlBuffer.append\(" ON"\);
statement.execute\(sqlBuffer.toString\(\)\);
\}

try
\{
\_operation.execute\(connection, new
DefaultDataSet\(table\)\);
\}
finally
\{
// disable identity insert
if \(hasIdentityColumn\)
\{
StringBuffer sqlBuffer = new
StringBuffer\(128\);
sqlBuffer.append\("SET
IDENTITY\_INSERT "\);

sqlBuffer.append\(getQualifiedName\(connection.getSchema\(\),
metaData.getTableName\(\),
connection\)\);
sqlBuffer.append\(" OFF"\);
statement.execute\(sqlBuffer.toString\(\)\);
\}
jdbcConnection.commit\(\);
\}
\}
\}
finally
\{
jdbcConnection.setAutoCommit\(true\);
statement.close\(\);
\}
\}

