int bufferDelta = 0;
StringBuffer buffer = new StringBuffer\(value\);

while \(\(startSearchIndex =
value.indexOf\(original, startSearchIndex\)\) \!= -1\) \{
int startReplaceIndex = startSearchIndex +
bufferDelta;
buffer.replace\(startReplaceIndex,
startReplaceIndex + original.length\(\), replacement\);
startSearchIndex += original.length\(\);
bufferDelta += replacement.length\(\) -
original.length\(\);
\}

value = buffer.toString\(\);
\}

return value;
