/\*\*
\* Gets the appropriate database connection, depending on whether we are using Oracle or HSQL.
\* 
\* @param schema
\* @param connection2
\* @return the appropriate IDatabaseConnection.
\* @throws SQLException if the database connection cannot be got.
\*/
private IDatabaseConnection getDatabaseConnection\(String schema, Connection pConnection\) throws SQLException
\{
String databaseProductName = getDatabaseName\(pConnection\);        
if \("Oracle".equals\(databaseProductName\)\)
\{
return new OracleConnection\(pConnection, schema\);
\}

if \("HSQL Database Engine".equals\(databaseProductName\)\)
\{
return new HsqldbConnection\(pConnection, schema\);
\}

// The default will do if we don't have either of the above.  Note that
// there are MORE funny connections that we don't cover here.
IDatabaseConnection connection = new DatabaseConnection\(pConnection, schema\);
return connection;
\}

