public class CorrectedColumnTable implements ITable
\{
private ITable originalTable;
private ITableMetaData fixedMetaData;
private Column originalColumn;
private Column fixedColumn;

public CorrectedColumnTable\(ITable table, String fixedColumnName, int fixedColIndex\) throws DataSetException \{
super\(\);
this.originalTable = table;

ITableMetaData originalMetaData = table.getTableMetaData\(\);
this.originalColumn = originalMetaData.getColumns\(\)\[fixedColIndex\];
this.fixedColumn = new Column\(fixedColumnName, this.originalColumn.getDataType\(\)\);
Column\[\] cols = new Column\[\] \{ this.fixedColumn \};
this.fixedMetaData = new DefaultTableMetaData\(originalMetaData.getTableName\(\), cols\);
\}

public ITableMetaData getTableMetaData\(\) \{
return this.fixedMetaData;
\}

public Object getValue\(int row, String column\) throws DataSetException \{
if\(this.fixedColumn.getColumnName\(\).equals\(column\)\)\{
return originalTable.getValue\(row, this.originalColumn.getColumnName\(\)\);
\}
return originalTable.getValue\(row, column\);
\}

public int getRowCount\(\) \{
return originalTable.getRowCount\(\);
\}
\}

