Mixing qualified table names, MySQL and DatabaseSequenceFilter leads to wrong table ordering and constraint violations when inserting data.

I'm not sure why exactly, the code involved in DatabaseSequenceFilter is way too complicated for what it has to do. I guess it's related to the fact that MySQL has no "schema" per se, and uses catalogs instead.

I don't quite understand why the DatabaseSequenceFilter class is so complicated; basically, what it needs to do is : create a graph of tables, where edges are table dependencies, check for cycles and perform a topological sort on it.

I rewrote it using JGrapht \(no need to reinvent the wheel\) and it's 100 lines long.

Here is how it looks; unfortunately, it's MySQL-dependent, because the current DBunit API doesn't allow for a database agnostic implementation without many contorsions \(IMHO, IMetaDataHandler lacks a few functions\).


package org.dbunit.util;

import org.apache.commons.lang.builder.EqualsBuilder;
import org.apache.commons.lang.builder.HashCodeBuilder;


public class CollectionFriendlyQualifiedTableName extends QualifiedTableName \{

	public CollectionFriendlyQualifiedTableName\(String tableName, String defaultSchema, String escapePattern\) \{
		super\(tableName, defaultSchema, escapePattern\);
	\}

	public CollectionFriendlyQualifiedTableName\(String tableName, String defaultSchema\) \{
		super\(tableName, defaultSchema\);
	\}
	
	@Override
	public boolean equals\(Object o\) \{
		if \(this == o\) \{
			return true;
		\}
		
		if \(\!\(o instanceof QualifiedTableName\)\) \{
			return false;
		\}
		
		QualifiedTableName n = \(QualifiedTableName\) o;
		
		return new EqualsBuilder\(\)
				.append\(getQualifiedName\(\).toUpperCase\(\), n.getQualifiedName\(\).toUpperCase\(\)\)
				.isEquals\(\);
	\}
	
	@Override
	public int hashCode\(\) \{
		return new HashCodeBuilder\(\)
				.append\(getQualifiedName\(\).toUpperCase\(\)\)
				.toHashCode\(\);
	\}
\}

//------------------------------------------------

package org.dbunit.database;

import java.sql.Connection;
import java.sql.DatabaseMetaData;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

import org.dbunit.dataset.DataSetException;
import org.dbunit.dataset.filter.SequenceTableFilter;
import org.dbunit.util.CollectionFriendlyQualifiedTableName;
import org.dbunit.util.QualifiedTableName;
import org.jgrapht.DirectedGraph;
import org.jgrapht.alg.CycleDetector;
import org.jgrapht.graph.DefaultDirectedGraph;
import org.jgrapht.traverse.TopologicalOrderIterator;


public class MySqlDatabaseSequenceFilter extends SequenceTableFilter \{
	
	public MySqlDatabaseSequenceFilter\(IDatabaseConnection databaseConnection\) throws DataSetException, SQLException \{
		this\(databaseConnection, databaseConnection.createDataSet\(\).getTableNames\(\)\);
	\}
	
	public MySqlDatabaseSequenceFilter\(IDatabaseConnection databaseConnection, String\[\] tableNames\) throws DataSetException, SQLException \{
		super\(sortTableNames\(databaseConnection, tableNames\)\);
	\}
		
	private static String\[\] sortTableNames\(IDatabaseConnection databaseConnection, String\[\] tableNames\) throws DataSetException, SQLException \{
		Connection connection = databaseConnection.getConnection\(\);
		DatabaseMetaData databaseMetadata = connection.getMetaData\(\);
		String defaultSchema = databaseConnection.getSchema\(\);
		DirectedGraph&lt;QualifiedTableName, Object&gt; graph = new DefaultDirectedGraph&lt;QualifiedTableName, Object&gt;\(Object.class\);
		DatabaseConfig databaseConfiguration = databaseConnection.getConfig\(\);
		String\[\] tableTypes = \(String\[\]\) databaseConfiguration.getProperty\(DatabaseConfig.PROPERTY\_TABLE\_TYPE\);
		
		for \(String tableName : tableNames\) \{
			QualifiedTableName qualifiedTableName = new CollectionFriendlyQualifiedTableName\(tableName, defaultSchema\);
			
			if \(qualifiedTableName.getSchema\(\) \!= null && qualifiedTableName.getSchema\(\).equals\(defaultSchema\)\) \{
				ResultSet tableResultSet = databaseMetadata.getTables\(defaultSchema, null, qualifiedTableName.getTable\(\), tableTypes\);
				
				try \{
					if \(tableResultSet.next\(\)\) \{
						graph.addVertex\(qualifiedTableName\);
						
						if \(tableResultSet.next\(\)\) \{
							throw new AmbiguousTableNameException\(tableName\);
						\}
					\}
				\} finally \{
					tableResultSet.close\(\);
				\}
			\}
		\}
		
		for \(QualifiedTableName qualifiedTableName : graph.vertexSet\(\)\) \{
			ResultSet importedKeysResultSet = databaseMetadata.getImportedKeys\(qualifiedTableName.getSchema\(\), null, qualifiedTableName.getTable\(\)\);
			
			try \{
				while \(importedKeysResultSet.next\(\)\) \{
					String referencedTableSchema = importedKeysResultSet.getString\(1\);
					String referencedTable = importedKeysResultSet.getString\(3\);
					QualifiedTableName qualifiedReferencedTableName = new CollectionFriendlyQualifiedTableName\(referencedTable, referencedTableSchema\);
					
					if \(graph.containsVertex\(qualifiedReferencedTableName\)\) \{
						graph.addEdge\(qualifiedTableName, qualifiedReferencedTableName\);
					\}
				\}
			\} finally \{
				importedKeysResultSet.close\(\);
			\}
		\}
		
		CycleDetector&lt;QualifiedTableName, Object&gt; cycleDetector = new CycleDetector&lt;QualifiedTableName, Object&gt;\(graph\);
		
		if \(cycleDetector.detectCycles\(\)\) \{
			throw new CyclicTablesDependencyException\("Table dependency cycle found"\);
		\}
		
		TopologicalOrderIterator&lt;QualifiedTableName, Object&gt; iterator = new TopologicalOrderIterator&lt;QualifiedTableName, Object&gt;\(graph\);
		List&lt;String&gt; result = new ArrayList&lt;String&gt;\(\);
		
		while \(iterator.hasNext\(\)\) \{
			result.add\(iterator.next\(\).getQualifiedName\(\)\);
		\}
		
		Collections.reverse\(result\);
		
		return result.toArray\(new String\[0\]\);
	\}
\}

